record_types.code:
type gsl_qrng is record
   c_type : access constant gsl_qrng_type;
   dimension  : aliased unsigned;
   state_size : aliased size_t;
   state      : System.Address;
end record;

type gsl_qrng_type is record
   name : Interfaces.C.Strings.chars_ptr;
   max_dimension : aliased unsigned;
   state_size    : access function
     (arg1 : unsigned) return size_t;
   init_state : access function
     (arg1 : System.Address; arg2 : unsigned)
      return int;
   get : access function
     (arg1 : System.Address; arg2 : unsigned; arg3 : access double)
      return int;
end record;
